     1→import React, { createContext, useContext, useEffect, useState } from 'react';
     2→import { getToken, setToken, clearToken, getStoredUser, setStoredUser, API_BASE } from '../lib/supabase';
     3→
     4→interface Profile {
     5→  id: string;
     6→  name: string;
     7→  email: string;
     8→  role: string;
     9→  company: string;
    10→  phone?: string;
    11→  avatar?: string;
    12→}
    13→
    14→interface AuthContextValue {
    15→  user: Profile | null;
    16→  profile: Profile | null;
    17→  loading: boolean;
    18→  isAuthenticated: boolean;
    19→  signIn: (email: string, password: string) => Promise<void>;
    20→  signUp: (email: string, password: string, name: string, company: string) => Promise<void>;
    21→  signOut: () => Promise<void>;
    22→  updateProfile: (updates: Partial<Profile>) => Promise<void>;
    23→}
    24→
    25→const AuthContext = createContext<AuthContextValue | null>(null);
    26→
    27→export function AuthProvider({ children }: { children: React.ReactNode }) {
    28→  const [user, setUser]       = useState<Profile | null>(null);
    29→  const [loading, setLoading] = useState(true);
    30→
    31→  // On mount, restore session from localStorage
    32→  useEffect(() => {
    33→    const token   = getToken();
    34→    const stored  = getStoredUser();
    35→    if (token && stored) {
    36→      setUser(stored as Profile);
    37→    }
    38→    setLoading(false);
    39→  }, []);
    40→
    41→  const signIn = async (email: string, password: string) => {
    42→    const res = await fetch(`${API_BASE}/auth/login`, {
    43→      method: 'POST',
    44→      headers: { 'Content-Type': 'application/json' },
    45→      body: JSON.stringify({ email, password }),
    46→    });
    47→    const data = await res.json();
    48→    if (!res.ok) throw new Error(data.message || 'Login failed');
    49→    setToken(data.token);
    50→    setStoredUser(data.user);
    51→    setUser(data.user as Profile);
    52→  };
    53→
    54→  const signUp = async (_email: string, _password: string, _name: string, _company: string) => {
    55→    // Self-registration is handled by admins — contact your admin for access
    56→    throw new Error('Self-registration is disabled. Contact your administrator for access.');
    57→  };
    58→
    59→  const signOut = async () => {
    60→    clearToken();
    61→    setUser(null);
    62→  };
    63→
    64→  const updateProfile = async (updates: Partial<Profile>) => {
    65→    const token = getToken();
    66→    if (!token || !user) return;
    67→    const res = await fetch(`${API_BASE}/auth/profile`, {
    68→      method: 'PUT',
    69→      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
    70→      body: JSON.stringify(updates),
    71→    });
    72→    const data = await res.json();
    73→    if (!res.ok) throw new Error(data.message || 'Update failed');
    74→    const updated = { ...user, ...data };
    75→    setUser(updated);
    76→    setStoredUser(updated);
    77→  };
    78→
    79→  return (
    80→    <AuthContext.Provider value={{
    81→      user,
    82→      profile: user,
    83→      loading,
    84→      isAuthenticated: !!user,
    85→      signIn,
    86→      signUp,
    87→      signOut,
    88→      updateProfile,
    89→    }}>
    90→      {children}
    91→    </AuthContext.Provider>
    92→  );
    93→}
    94→
    95→export function useAuth() {
    96→  const ctx = useContext(AuthContext);
    97→  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
    98→  return ctx;
    99→}
