    11→async function apiFetch<T>(path: string, options?: RequestInit): Promise<T> {
    12→  const token = getToken();
    13→  const res = await fetch(`${API_BASE}${path}`, {
    14→    ...options,
    15→    headers: {
    16→      'Content-Type': 'application/json',
    17→      ...(token ? { Authorization: `Bearer ${token}` } : {}),
    18→      ...options?.headers,
    19→    },
    20→  });
    21→  if (!res.ok) {
    22→    const err = await res.json().catch(() => ({ message: res.statusText }));
    23→    throw new Error(err.message || 'Request failed');
    24→  }
    25→  return res.json();
    26→}
