     1→const express = require('express');
     2→const pool    = require('../db');
     3→
     4→/**
     5→ * Creates a standard CRUD router for any table.
     6→ * @param {string} tableName - The PostgreSQL table name
     7→ * @param {string} [orderCol='created_at'] - Column to order by
     8→ */
     9→function makeRouter(tableName, orderCol = 'created_at') {
    10→  const router = express.Router();
    11→
    12→  // GET / — list all
    13→  router.get('/', async (req, res) => {
    14→    try {
    15→      const { rows } = await pool.query(`SELECT * FROM ${tableName} ORDER BY ${orderCol} DESC`);
    16→      res.json(rows);
    17→    } catch (err) {
    18→      console.error(`[GET ${tableName}]`, err.message);
    19→      res.status(500).json({ message: err.message });
    20→    }
    21→  });
    22→
    23→  // GET /:id — get one
    24→  router.get('/:id', async (req, res) => {
    25→    try {
    26→      const { rows } = await pool.query(`SELECT * FROM ${tableName} WHERE id = $1`, [req.params.id]);
    27→      if (!rows[0]) return res.status(404).json({ message: 'Not found' });
    28→      res.json(rows[0]);
    29→    } catch (err) {
    30→      res.status(500).json({ message: err.message });
    31→    }
    32→  });
    33→
    34→  // POST / — create
    35→  router.post('/', async (req, res) => {
    36→    const data = req.body;
    37→    const keys = Object.keys(data).filter(k => data[k] !== undefined);
    38→    if (!keys.length) return res.status(400).json({ message: 'No data provided' });
    39→
    40→    const cols    = keys.join(', ');
    41→    const placeholders = keys.map((_, i) => `$${i + 1}`).join(', ');
    42→    const values  = keys.map(k => data[k]);
    43→
    44→    try {
    45→      const { rows } = await pool.query(
    46→        `INSERT INTO ${tableName} (${cols}) VALUES (${placeholders}) RETURNING *`,
    47→        values
    48→      );
    49→      res.status(201).json(rows[0]);
    50→    } catch (err) {
    51→      console.error(`[POST ${tableName}]`, err.message);
    52→      res.status(500).json({ message: err.message });
    53→    }
    54→  });
    55→
    56→  // PUT /:id — update
    57→  router.put('/:id', async (req, res) => {
    58→    const data = req.body;
    59→    const keys = Object.keys(data).filter(k => data[k] !== undefined);
    60→    if (!keys.length) return res.status(400).json({ message: 'No data provided' });
    61→
    62→    const setClause = keys.map((k, i) => `${k} = $${i + 1}`).join(', ');
    63→    const values    = [...keys.map(k => data[k]), req.params.id];
    64→
    65→    try {
    66→      const { rows } = await pool.query(
    67→        `UPDATE ${tableName} SET ${setClause} WHERE id = $${keys.length + 1} RETURNING *`,
    68→        values
    69→      );
    70→      if (!rows[0]) return res.status(404).json({ message: 'Not found' });
    71→      res.json(rows[0]);
    72→    } catch (err) {
    73→      console.error(`[PUT ${tableName}]`, err.message);
    74→      res.status(500).json({ message: err.message });
    75→    }
    76→  });
    77→
    78→  // DELETE /:id
    79→  router.delete('/:id', async (req, res) => {
    80→    try {
    81→      const { rowCount } = await pool.query(`DELETE FROM ${tableName} WHERE id = $1`, [req.params.id]);
    82→      if (!rowCount) return res.status(404).json({ message: 'Not found' });
    83→      res.json({ message: 'Deleted successfully' });
    84→    } catch (err) {
    85→      res.status(500).json({ message: err.message });
    86→    }
    87→  });
    88→
    89→  return router;
    90→}
    91→
    92→module.exports = makeRouter;
    93→

